// src/pages/PageNotFound.jsx
import React from "react";
import { Link } from "react-router-dom";
import { Navbar, Footer } from "../components";
import { Home, ArrowLeft, Search, Frown } from "lucide-react";

const PageNotFound = () => {
  return (
    <>
      <Navbar />

      <div className="not-found-page py-5">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-md-8 col-lg-6">
              <div className="not-found-card bg-white rounded-4 shadow-lg overflow-hidden text-center">

                {/* Image/Illustration */}
                <div className="not-found-image bg-primary bg-opacity-10 py-5">
                  <div className="position-relative d-inline-block">
                    <span className="display-1 fw-bold text-primary opacity-25">404</span>
                    <Frown 
                      size={80} 
                      className="text-primary position-absolute top-50 start-50 translate-middle" 
                    />
                  </div>
                </div>

                {/* Contenu */}
                <div className="not-found-content p-5">
                  <h1 className="display-4 fw-bold mb-3">
                    Page non trouvée
                  </h1>

                  <p className="lead text-muted mb-4">
                    Désolé, la page que vous recherchez n'existe pas ou a été déplacée.
                  </p>

                  {/* Suggestions */}
                  <div className="suggestions bg-light rounded-3 p-4 mb-4 text-start">
                    <h6 className="fw-bold mb-3">Vous pouvez :</h6>
                    <ul className="list-unstyled mb-0">
                      <li className="mb-2 d-flex align-items-center">
                        <span className="badge bg-primary bg-opacity-10 text-primary rounded-circle p-2 me-3">
                          <Home size={14} />
                        </span>
                        <span>Retourner à la <Link to="/" className="text-primary text-decoration-none fw-semibold">page d'accueil</Link></span>
                      </li>
                      <li className="mb-2 d-flex align-items-center">
                        <span className="badge bg-primary bg-opacity-10 text-primary rounded-circle p-2 me-3">
                          <Search size={14} />
                        </span>
                        <span>Utiliser la <Link to="/product" className="text-primary text-decoration-none fw-semibold">recherche de produits</Link></span>
                      </li>
                      <li className="d-flex align-items-center">
                        <span className="badge bg-primary bg-opacity-10 text-primary rounded-circle p-2 me-3">
                          <ArrowLeft size={14} />
                        </span>
                        <span>Vérifier l'URL ou <button 
                          onClick={() => window.history.back()} 
                          className="btn btn-link text-primary text-decoration-none fw-semibold p-0"
                        >
                          revenir en arrière
                        </button></span>
                      </li>
                    </ul>
                  </div>

                  {/* Liens rapides */}
                  <div className="quick-links mb-4">
                    <h6 className="fw-bold mb-3">Pages populaires :</h6>
                    <div className="d-flex flex-wrap gap-2 justify-content-center">
                      <Link to="/product" className="btn btn-outline-primary btn-sm rounded-pill">
                        Produits
                      </Link>
                      <Link to="/about" className="btn btn-outline-primary btn-sm rounded-pill">
                        À propos
                      </Link>
                      <Link to="/contact" className="btn btn-outline-primary btn-sm rounded-pill">
                        Contact
                      </Link>
                      <Link to="/cart" className="btn btn-outline-primary btn-sm rounded-pill">
                        Panier
                      </Link>
                    </div>
                  </div>

                  {/* Bouton principal */}
                  <Link 
                    to="/" 
                    className="btn btn-primary btn-lg rounded-pill px-5 py-3 d-inline-flex align-items-center gap-2 mx-auto"
                  >
                    <Home size={20} />
                    Retour à l'accueil
                  </Link>

                  {/* Lien secondaire */}
                  <div className="mt-4">
                    <button 
                      onClick={() => window.history.back()} 
                      className="btn btn-link text-muted text-decoration-none d-inline-flex align-items-center gap-2"
                    >
                      <ArrowLeft size={16} />
                      Revenir à la page précédente
                    </button>
                  </div>
                </div>
              </div>

              {/* Message de support */}
              <div className="support-message text-center mt-4">
                <p className="small text-muted">
                  Si vous pensez qu'il s'agit d'une erreur, 
                  <Link to="/contact" className="text-primary text-decoration-none fw-semibold ms-1">
                    contactez notre support
                  </Link>
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Footer />

      {/* Styles personnalisés */}
      <style jsx>{`
        .not-found-card {
          border: none;
          transition: transform 0.3s ease;
        }
        .not-found-card:hover {
          transform: translateY(-5px);
        }
        .not-found-image {
          position: relative;
          overflow: hidden;
        }
        .not-found-image::before {
          content: '';
          position: absolute;
          top: -50%;
          left: -50%;
          width: 200%;
          height: 200%;
          background: radial-gradient(circle, rgba(13,110,253,0.1) 0%, transparent 70%);
          animation: rotate 20s linear infinite;
        }
        @keyframes rotate {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .suggestions ul li {
          transition: transform 0.3s ease;
        }
        .suggestions ul li:hover {
          transform: translateX(5px);
        }
        @media (max-width: 768px) {
          .display-4 {
            font-size: 2.5rem;
          }
          .not-found-content {
            padding: 2rem !important;
          }
        }
      `}</style>
    </>
  );
};

export default PageNotFound;
